export interface DurationObservation {
  duration: number
  recordedAt: number
}

/**
 * Reduce a list of non-expired duration observations for a single file into a
 * single representative duration using the configured smoothing strategy.
 *
 * An empty list always resolves to `0`.
 */
export function smoothDuration(
  observations: DurationObservation[],
  smoothing: DurationSmoothing,
): number {
  if (observations.length === 0) {
    return 0
  }

  switch (smoothing) {
    case 'latest': {
      let latest = observations[0]
      for (const observation of observations) {
        if (observation.recordedAt > latest.recordedAt) {
          latest = observation
        }
      }
      return latest.duration
    }
    case 'average': {
      const sum = observations.reduce((total, o) => total + o.duration, 0)
      return Math.round(sum / observations.length)
    }
    case 'p95': {
      const sorted = observations.map(o => o.duration).sort((a, b) => a - b)
      const index = Math.ceil(0.95 * sorted.length) - 1
      return sorted[index]
    }
    case 'median': {
      const sorted = observations.map(o => o.duration).sort((a, b) => a - b)
      const n = sorted.length
      if (n % 2 === 1) {
        return sorted[(n - 1) / 2]
      }
      const a = sorted[n / 2 - 1]
      const b = sorted[n / 2]
      return Math.floor((a + b) / 2)
    }
  }
}
