import fs from 'node:fs'
import { dirname, isAbsolute, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'
import { smoothDuration } from './duration-smoothing'

/**
 * On-disk representation of a single file entry in the duration history file.
 * Three shapes are supported for backwards/forwards compatibility:
 * - legacy: a bare number (milliseconds)
 * - single: `{ duration, recordedAt }`
 * - multi:  `{ observations: [{ duration, recordedAt }, ...] }`
 */
export type RawHistoryEntry
  = | number
    | { duration: number, recordedAt: number }
    | { observations: DurationObservation[] }

export type RawDurationHistory = Record<string, RawHistoryEntry>

export interface ReadDurationHistoryOptions {
  root: string
  historyPath: string
  ttl: number
  smoothing: DurationSmoothing
}

function resolveHistoryPath(root: string, historyPath: string): string {
  return isAbsolute(historyPath) ? historyPath : resolve(root, historyPath)
}

/**
 * Normalize any of the supported raw entry shapes into a flat list of
 * observations. Legacy numeric entries are migrated to a single observation
 * with `recordedAt: 0` (an epoch that never expires).
 */
export function normalizeEntry(entry: RawHistoryEntry): DurationObservation[] {
  if (typeof entry === 'number') {
    return [{ duration: entry, recordedAt: 0 }]
  }
  if (entry && typeof entry === 'object') {
    if (Array.isArray((entry as { observations?: unknown }).observations)) {
      return (entry as { observations: DurationObservation[] }).observations
        .filter(o => o && typeof o.duration === 'number' && typeof o.recordedAt === 'number')
    }
    if (typeof (entry as { duration?: unknown }).duration === 'number') {
      const single = entry as { duration: number, recordedAt?: number }
      return [{ duration: single.duration, recordedAt: single.recordedAt ?? 0 }]
    }
  }
  return []
