 * If the least-loaded shard is disproportionately lighter than the heaviest one
 * (`minLoad / maxLoad < threshold`), emit a warning so the user knows the shards
 * are poorly balanced. The message always contains the `ratio=` and `threshold=`
 * fields, each formatted to two decimals.
 *
 * A `threshold` of `0` disables the check; an all-zero load set is skipped to
 * avoid a division by zero.
 */
export function checkRebalanceThreshold(
  loads: number[],
  threshold: number,
  warn: (message: string) => void,
): void {
  if (threshold <= 0 || loads.length === 0) {
    return
  }
  const maxLoad = Math.max(...loads)
  if (maxLoad === 0) {
    return
  }
  const minLoad = Math.min(...loads)
  const ratio = minLoad / maxLoad
  if (ratio < threshold) {
    warn(
      `[vitest] Shard load imbalance detected: ratio=${ratio.toFixed(2)} is below threshold=${threshold.toFixed(2)}. `
      + `Consider recording fresh file durations or adjusting the shard strategy.`,
    )
  }
}

/**
 * Sort items by their recorded duration DESC. Items whose path is absent from
 * the duration history are ordered last (after every known-duration item),
 * preserving a stable path-based order among themselves.
 */
export function sortByDurationHistory<T>(
  items: T[],
  getPath: (item: T) => string,
  history: Map<string, number>,
): T[] {
  return [...items].sort((a, b) => {
    const pathA = getPath(a)
    const pathB = getPath(b)
    const hasA = history.has(pathA)
    const hasB = history.has(pathB)

    if (hasA !== hasB) {
      return hasA ? -1 : 1
    }
    if (!hasA) {
      return pathA < pathB ? -1 : pathA > pathB ? 1 : 0
    }

    const durationA = history.get(pathA)!
    const durationB = history.get(pathB)!
    if (durationB !== durationA) {
      return durationB - durationA
    }
    return pathA < pathB ? -1 : pathA > pathB ? 1 : 0
  })
}
