  const { root, ctx } = await runInlineTests({
    'a.test.ts': ts`
      import { test, expect } from 'vitest'
      test('a', () => { expect(1).toBe(1) })
    `,
    'b.test.ts': ts`
      import { test, expect } from 'vitest'
      test('b', () => { expect(2).toBe(2) })
    `,
    'vitest.config.ts': ts`
      export default {
        test: {
          sequence: {
            recordFileDurations: true,
          },
        },
      }
    `,
  })

  expect(ctx?.state.getFiles().length).toBe(2)

  const historyPath = join(root, 'duration-history.json')
  expect(existsSync(historyPath)).toBe(true)

  const history = JSON.parse(readFileSync(historyPath, 'utf8'))
  expect(Object.keys(history).sort()).toEqual(['a.test.ts', 'b.test.ts'])
  for (const key of Object.keys(history)) {
    expect(history[key]).toHaveProperty('duration')
    expect(history[key]).toHaveProperty('recordedAt')
    expect(Number.isInteger(history[key].duration)).toBe(true)
    expect(history[key].duration).toBeGreaterThanOrEqual(0)
  }
})

